const keyLight = new THREE.DirectionalLight(0xfff0f8, 1.4);
keyLight.position.set(3, 6, 5);
keyLight.castShadow = true;
keyLight.shadow.mapSize.set(1024,1024);
scene.add(keyLight);

const fillLight = new THREE.DirectionalLight(0x8060ff, 0.4);
fillLight.position.set(-4, 2, 3);
scene.add(fillLight);

const rimLight = new THREE.DirectionalLight(0x6040ff, 0.5);
rimLight.position.set(0, 3, -6);
scene.add(rimLight);

// Floor glow
const floorGeo = new THREE.CircleGeometry(2.5, 32);
const floorMat = new THREE.MeshBasicMaterial({color:0x200840, transparent:true, opacity:0.6});
