scene.add(new THREE.Points(partGeo,partMat));

// ── REAL 3D MESH (импортированная и сконвертированная модель FinalBaseMesh) ──
// Геометрия встроена в файл как base64 (позиции/нормали/индексы), чтобы
// страница оставалась одним самодостаточным HTML-файлом без внешних .obj/.mtl.
const MESH_B64_POS = "";
const MESH_B64_NORM = "";
const MESH_B64_IDX = "";
const MESH_NVERTS = 24461;
const MESH_NINDICES = 146754;

function b64ToBytes(b64){
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for(let i=0;i<bin.length;i++) bytes[i]=bin.charCodeAt(i);
  return bytes;
}
function b64ToFloat32(b64){ return new Float32Array(b64ToBytes(b64).buffer); }
function b64ToUint16(b64){ return new Uint16Array(b64ToBytes(b64).buffer); }

const meshPositions = b64ToFloat32(MESH_B64_POS);
const meshNormals   = b64ToFloat32(MESH_B64_NORM);
const meshIndices   = b64ToUint16(MESH_B64_IDX);

const bodyGeo = new THREE.BufferGeometry();
bodyGeo.setAttribute('position', new THREE.BufferAttribute(meshPositions, 3));
bodyGeo.setAttribute('normal', new THREE.BufferAttribute(meshNormals, 3));
bodyGeo.setIndex(new THREE.BufferAttribute(meshIndices, 1));

const bodyMat = new THREE.MeshStandardMaterial({color:0x2a2045, roughness:0.62, metalness:0.06});
const bodyMesh = new THREE.Mesh(bodyGeo, bodyMat);
bodyMesh.castShadow = true;
bodyMesh.receiveShadow = true;
bodyMesh.userData.isBodyMesh = true;
scene.add(bodyMesh);

// ── ZONE HOTSPOTS — маркеры-точки на поверхности реального меша ──
// Координаты вычислены заранее из геометрии модели (анатомические ориентиры
// по высоте + сторона X + выступ вперёд/назад по Z), затем чуть вынесены
// наружу от поверхности, чтобы маркер всегда был кликабелен поверх кожи.
const ZONE_MARKERS = {
  forehead:[-0.0482,3.2703,0.359],
  crown:[-0.0,3.5836,0.0692],
  occiput:[-0.0,3.1718,-0.4324],
  temple_l:[0.2302,3.1144,-0.3409],
  temple_r:[-0.2294,3.1145,-0.3403],
  jaw:[0.0,2.7295,0.3814],
  eyes:[-0.0,3.0023,0.4717],
  ears:[0.2504,2.868,0.1017],
  nose:[-0.0,2.8886,0.4228],
  neck:[0.0,2.517,0.1279],
  chest:[0.0384,1.1119,0.4227],
  lshoulder:[0.7502,1.8917,0.0572],
  rshoulder:[-0.75,1.8917,0.0572],
  larm:[0.6934,1.6682,-0.0302],
  rarm:[-0.6934,1.6682,-0.0302],
  abdomen:[-0.0003,0.1995,0.4263],
  pelvis:[0.0007,-0.1332,0.4018],
  lleg:[0.5001,-1.1716,0.2839],
  rleg:[-0.5001,-1.1716,0.2839]
};

function pushOutward(p, dist){
  const len = Math.hypot(p[0], p[2]) || 1;
  return [ p[0] + (p[0]/len)*dist, p[1], p[2] + (p[2]/len)*dist ];
}

const bodyParts = []; // {mesh, zone, origHex} — теперь это маркеры-хотспоты, не части тела

Object.entries(ZONE_MARKERS).forEach(([key,p])=>{
  const z = ZONES[key];
  if(!z) return;
  const pos = pushOutward(p, 0.065);
  const geo = new THREE.SphereGeometry(0.075, 14, 12);
  const mat = new THREE.MeshStandardMaterial({color:z.col, emissive:z.em, emissiveIntensity:0.4, roughness:0.35, metalness:0.15});
  const marker = new THREE.Mesh(geo, mat);
  marker.position.set(pos[0], pos[1], pos[2]);
  marker.userData.zone = key;
  marker.userData.baseScale = 1;
  scene.add(marker);
  bodyParts.push({mesh:marker, zone:key, origHex:z.col});
});

// ── LEGEND ──
const mapEl = document.getElementById('zone-map');
// Group zones for legend — show head zones together, then body
const headZoneKeys = ['forehead','temple_l','temple_r','crown','occiput','jaw','eyes','ears','nose','neck'];
const bodyZoneKeys = ['chest','lshoulder','rshoulder','larm','rarm','abdomen','pelvis','lleg','rleg'];

// Zone map (right overlay) — just body zones to keep it compact
bodyZoneKeys.forEach(k=>{
  if(!ZONES[k]) return;
  const z = ZONES[k];
  const hex = '#' + z.col.toString(16).padStart(6,'0');
  const div = document.createElement('div');
  div.className='zm-item';
  div.innerHTML=`<div class="zm-dot" style="background:${hex}"></div>${z.name}`;
  div.onclick = ()=>{ highlightZone(k); };
  mapEl.appendChild(div);
});

