// ORGAN 3D VIEWER
// ═══════════════════════════════════════════════
const oCanvas=document.getElementById('oCanvas');
let oRenderer=null,oScene=null,oCamera=null,oGroup=null,oAnim=false,oRot=0;

function initOrganRenderer(){
  if(oRenderer)return;
  const wrap=document.getElementById('organ-canvas-wrap');
  const w=wrap.clientWidth||340, h=200;
  oRenderer=new THREE.WebGLRenderer({canvas:oCanvas,antialias:true,alpha:true});
  oRenderer.setSize(w,h);
  oRenderer.setPixelRatio(Math.min(window.devicePixelRatio,2));
  oScene=new THREE.Scene();
  oCamera=new THREE.PerspectiveCamera(48,w/h,0.1,50);
  oCamera.position.set(0,0,4.5);
  oScene.add(new THREE.AmbientLight(0xffffff,0.55));
  const ol=new THREE.DirectionalLight(0xffffff,1.2);ol.position.set(2,3,4);oScene.add(ol);
  const ob=new THREE.DirectionalLight(0xa78bfa,0.4);ob.position.set(-2,-1,-3);oScene.add(ob);
  oGroup=new THREE.Group();oScene.add(oGroup);
}

function clearOrgan(){ if(oGroup)while(oGroup.children.length)oGroup.remove(oGroup.children[0]); }

function oMat(hex,op=1){
  return new THREE.MeshStandardMaterial({color:hex,roughness:0.5,metalness:0.05,transparent:op<1,opacity:op});
}

function runOrganAnim(){
  if(!oAnim)return;
  requestAnimationFrame(runOrganAnim);
  oRot+=0.006;
  if(oGroup)oGroup.rotation.y=oRot;
  if(oRenderer&&oScene&&oCamera)oRenderer.render(oScene,oCamera);
}

